using UnityEngine;

/// <summary>
/// Helper estático para a "câmara lenta" das rodas (Roda de Animais —
/// FormWheelUI, Roda de Itens — ItemWheelUI): aplica um Time.timeScale
/// reduzido (ex: 0.2) enquanto qualquer uma das rodas estiver aberta, sem
/// pausar totalmente o jogo (diferente de <see cref="GamePauseUtil"/>, que usa
/// Time.timeScale = 0).
///
/// Com contagem de referências (_activeCount): se, por algum motivo, as duas
/// rodas pedirem câmara lenta "ao mesmo tempo", só a última a fechar restaura
/// o Time.timeScale original — evita que uma roda restaure o tempo normal
/// enquanto a outra ainda está aberta.
///
/// Verifica <see cref="GamePauseUtil.IsPaused"/> para não conflituar com o
/// Menu de Pausa (Time.timeScale = 0 tem prioridade — não substituído por 0.2).
/// </summary>
public static class WheelTimeScaleUtil
{
    private static float _savedTimeScale = 1f;
    private static int _activeCount;

    public static bool IsActive => _activeCount > 0;

    /// <summary>Pede câmara lenta a "scale" (ex: 0.2). Seguro chamar mesmo se já estiver activa.</summary>
    public static void BeginSlowdown(float scale)
    {
        if (_activeCount == 0)
            _savedTimeScale = Time.timeScale;

        _activeCount++;

        if (!GamePauseUtil.IsPaused)
            Time.timeScale = scale;
    }

    /// <summary>Liberta um pedido de câmara lenta. Só restaura o tempo normal quando todos os pedidos tiverem sido libertados.</summary>
    public static void EndSlowdown()
    {
        if (_activeCount == 0) return;

        _activeCount--;

        if (_activeCount == 0 && !GamePauseUtil.IsPaused)
            Time.timeScale = _savedTimeScale;
    }
}
